    # Example reward function: negative squared norm of state and action
    def quadratic_reward(state: np.ndarray, action: np.ndarray) -> float:
        return - (np.linalg.norm(state) ** 2 + np.linalg.norm(action) ** 2)

    relabeled = relabel_transitions(dummy_dataset, quadratic_reward)

